    DECLARE @dropUniqueIndexes nvarchar(max) = N'';

    SELECT @dropUniqueIndexes = @dropUniqueIndexes
        + CASE
            WHEN i.is_unique_constraint = 1 THEN
                N'ALTER TABLE ' + QUOTENAME(OBJECT_SCHEMA_NAME(i.object_id))
